#include <stdio.h>

int main() {

    int N;
    scanf("%d",&N);

    int A[N];

    for(int i = 0; i < N; i++){
        scanf("%d", &A[i]);
    }

    int sum = 0;

    for(int i = 0; i < N; i++){
        sum = sum + A[i];
    }

    printf("%d", sum);

    return 0;
}

code.Java:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        // Create a Scanner object for input
        Scanner scanner = new Scanner(System.in);

        // Read the input size
        int n = scanner.nextInt();

        // Create an array to hold the elements
        int[] arr = new int[n];

        // Read the array elements
        for (int i = 0; i < n; i++) {
            arr[i] = scanner.nextInt();
        }

        // Calculate the sum of array elements
        int totalSum = 0;
        for (int i = 0; i < n; i++) {
            totalSum += arr[i];
        }

        // Print the sum
        System.out.println(totalSum);

        // Close the scanner
        scanner.close();
    }
}

