const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

function main() {
    let input = [];

    rl.on('line', (line) => {
        input.push(line);
    });

    rl.on('close', () => {

        let size = parseInt(input[0]);
        let elements = input[1].split(' ').map(Number);

        let sum = elements.reduce((acc, num) => acc + num, 0);
        console.log(sum);
    });
}

